import React from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const Hero = () => {
  return (
    <section className="home-hero" aria-label="Introduction">
      <div className="container home-hero__inner">
        <div className="home-hero__content">
          <h1 className="home-hero__title">
            We turn founder led agency businesses into highly profitable, cash confident companies
          </h1>
          <p className="home-hero__lead">
            Go from making gut based decisions to having total financial clarity
          </p>
          <Link to="/contact" className="btn-primary btn-large home-hero__cta">
            Schedule a Call
          </Link>
        </div>
      </div>
    </section>
  );
};

export default Hero;
